            shutil.rmtree(config_dir, ignore_errors=True)

        # Remove root files
        for filename in [".env", "requirements.txt", "test_file.json"]:
            file_path = os.path.join(base_test_data_dir, filename)
            if os.path.exists(file_path):
                os.remove(file_path)

        # Remove deprecated nested directory
        nested_dir = os.path.join(base_test_data_dir, "nested")
        if os.path.exists(nested_dir):
            shutil.rmtree(nested_dir, ignore_errors=True)

        # Remove corrupted files
        for item in os.listdir(base_test_data_dir):
            if (
                item.startswith("tmp") and ".corrupted_" in item
            ) or ".corrupted_" in item:
                item_path = os.path.join(base_test_data_dir, item)
                if os.path.isfile(item_path):
                    os.remove(item_path)

        # Clear tmp directory completely - remove all subdirectories and files
        tmp_dir = os.path.join(base_test_data_dir, "tmp")
        if os.path.exists(tmp_dir):
            try:
                # Remove all contents (subdirectories and files)
                for item in os.listdir(tmp_dir):
                    item_path = os.path.join(tmp_dir, item)
                    try:
                        if os.path.isdir(item_path):
                            shutil.rmtree(item_path, ignore_errors=True)
                        else:
                            os.remove(item_path)
                    except Exception:
                        pass
                # Directory itself stays but is now empty
            except Exception:
                pass

        # Clear flags directory completely
        flags_dir = os.path.join(base_test_data_dir, "flags")
        if os.path.exists(flags_dir):
            try:
                for item in os.listdir(flags_dir):
                    item_path = os.path.join(flags_dir, item)
                    try:
                        if os.path.isfile(item_path):
                            os.remove(item_path)
                        elif os.path.isdir(item_path):
                            shutil.rmtree(item_path, ignore_errors=True)
                    except Exception:
                        pass
            except Exception:
                pass

        # Clear requests directory completely
        requests_dir = os.path.join(base_test_data_dir, "requests")
        if os.path.exists(requests_dir):
            try:
                for item in os.listdir(requests_dir):
                    item_path = os.path.join(requests_dir, item)
                    try:
                        if os.path.isfile(item_path):
                            os.remove(item_path)
                        elif os.path.isdir(item_path):
                            shutil.rmtree(item_path, ignore_errors=True)
                    except Exception:
                        pass
            except Exception:
                pass

        # Clean up conversation_states.json
        conversation_states_file = os.path.join(
            base_test_data_dir, "conversation_states.json"
        )
        if os.path.exists(conversation_states_file):
            with contextlib.suppress(Exception):
                os.remove(conversation_states_file)

        # Clear logs directory
        logs_dir = os.path.join(base_test_data_dir, "logs")
        if os.path.exists(logs_dir):
            shutil.rmtree(logs_dir, ignore_errors=True)

        # Clean up old test_run files in tests/logs (but preserve current session files)
        test_logs_dir = os.path.join(project_root, "tests", "logs")
        if os.path.exists(test_logs_dir):
            try:
                for item in os.listdir(test_logs_dir):
                    # Only clean up old test_run files, not the current session's test_run.log
                    if (
                        item.startswith("test_run_")
                        and item.endswith(".log")
                        and item != "test_run.log"
                    ):
                        item_path = os.path.join(test_logs_dir, item)
                        if os.path.isfile(item_path):
                            os.remove(item_path)
            except Exception:
                pass

        # Clean up any stray test.log files in tests/data
        try:
            for root, _dirs, files in os.walk(base_test_data_dir):
                for file in files:
                    if file == "test.log":
                        file_path = os.path.join(root, file)
                        with contextlib.suppress(Exception):
                            os.remove(file_path)
        except Exception:
            pass

    except Exception:
        pass  # Ignore cleanup errors

"""
Factory for creating test users with different configurations.
"""

import os
import json
import logging
import copy

from typing import Any

from core.time_utilities import now_timestamp_full

logger = logging.getLogger(__name__)


class TestUserFactory:
    """Factory for creating test users with different configurations"""

    # Cache for pre-created user data structures to avoid recreating identical data
    _user_data_cache: dict[str, dict[str, Any]] = {}

    @staticmethod
    def _get_cache_key(
        enable_checkins: bool | None = None,
        enable_tasks: bool | None = None,
        user_type: str = "basic",
        **kwargs,
    ) -> str:
        """Generate a cache key for user data structures (configuration only, not user_id)."""
        # For user types with fixed configurations, use just the type
        if user_type in (
            "minimal",
            "full",
            "discord",
            "email",
            "health",
            "task",
            "complex_checkins",
            "disability",
            "limited_data",
            "inconsistent",
        ):
            return f"{user_type}"
        # For basic users, include checkins and tasks in the key
        return f"{user_type}:checkins={enable_checkins}:tasks={enable_tasks}"

    @staticmethod
    def _get_cached_user_data(cache_key: str) -> dict[str, Any] | None:
        """Get cached user data structure if available."""
        return TestUserFactory._user_data_cache.get(cache_key)

    @staticmethod
    def _cache_user_data(cache_key: str, user_data: dict[str, Any]):
        """Cache a user data structure for reuse."""
        # Use deepcopy to ensure the cached template is independent
        TestUserFactory._user_data_cache[cache_key] = copy.deepcopy(user_data)

    @staticmethod
    def clear_cache():
        """Clear the user data cache (useful for test cleanup)."""
        TestUserFactory._user_data_cache.clear()

    @staticmethod
    def create_basic_user(
        user_id: str,
        enable_checkins: bool = True,
        enable_tasks: bool = True,
        test_data_dir: str | None = None,
    ) -> bool:
        """
        Create a test user with basic functionality enabled

        Args:
            user_id: Unique identifier for the test user
            enable_checkins: Whether to enable check-ins for this user
            enable_tasks: Whether to enable task management for this user
            test_data_dir: Test data directory to use (if None, uses real user directory)

        Returns:
            bool: True if user was created successfully, False otherwise
        """
        try:
            # test_data_dir is now required - all tests should use the modern approach
            if not test_data_dir:
                raise ValueError(
                    "test_data_dir parameter is required - use modern test approach"
                )
            return TestUserFactory.create_basic_user__with_test_dir(
                user_id, enable_checkins, enable_tasks, test_data_dir
            )

        except Exception as e:
            logger.error(f"Error creating basic user {user_id}: {e}")
            return False

    @staticmethod
    def _create_user_files_directly__directory_structure(
        test_data_dir: str, user_id: str
    ) -> tuple[str, str]:
        """Create the user directory structure and return paths."""
        # Create test users directory
        test_users_dir = os.path.join(test_data_dir, "users")
        os.makedirs(test_users_dir, exist_ok=True)

        # Generate UUID for the user
        import uuid

        actual_user_id = str(uuid.uuid4())

        # Create user directory
        user_dir = os.path.join(test_users_dir, actual_user_id)
        os.makedirs(user_dir, exist_ok=True)

        return actual_user_id, user_dir

    @staticmethod
    def _create_user_files_directly__account_data(
        actual_user_id: str, user_id: str, user_data: dict
    ) -> dict:
        """Create account data structure."""
        return {
            "user_id": actual_user_id,
            "internal_username": user_id,
            "account_status": "active",
            "chat_id": user_data.get("chat_id", ""),
            "phone": user_data.get("phone", ""),
            "email": user_data.get("email", ""),
            "discord_user_id": user_data.get("discord_user_id", ""),
            "created_at": now_timestamp_full(),
            "updated_at": now_timestamp_full(),
            "features": {
                "automated_messages": (
                    "enabled" if user_data.get("categories") else "disabled"
                ),
                "checkins": (
                    "enabled"
                    if user_data.get("checkin_settings", {}).get("enabled", False)
                    else "disabled"
                ),
                "task_management": (
                    "enabled"
                    if user_data.get("task_settings", {}).get("enabled", False)
                    else "disabled"
                ),
            },
            "timezone": user_data.get("timezone", ""),
        }

    @staticmethod
    def _create_user_files_directly__preferences_data(user_data: dict) -> dict:
        """Create preferences data structure."""
        preferences_data = {
            "categories": user_data.get("categories", []),
            "channel": {"type": user_data.get("channel", {}).get("type", "email")},
            "checkin_settings": user_data.get("checkin_settings", {}),
            "task_settings": user_data.get("task_settings", {}),
        }

        # Remove redundant enabled flags from preferences since they're in account.json features
        if (
            "checkin_settings" in preferences_data
            and "enabled" in preferences_data["checkin_settings"]
        ):
            del preferences_data["checkin_settings"]["enabled"]
        if (
            "task_settings" in preferences_data
            and "enabled" in preferences_data["task_settings"]
        ):
            del preferences_data["task_settings"]["enabled"]

        return preferences_data

    @staticmethod
    def _create_user_files_directly__context_data(user_data: dict) -> dict:
        """Create user context data structure."""
        return {
            "preferred_name": user_data.get("preferred_name", ""),
            "gender_identity": user_data.get("gender_identity", []),
            "date_of_birth": user_data.get("date_of_birth", ""),
            "custom_fields": {
                "reminders_needed": user_data.get("reminders_needed", []),
                "health_conditions": user_data.get("custom_fields", {}).get(
                    "health_conditions", []
                ),
                "medications_treatments": user_data.get("custom_fields", {}).get(
                    "medications_treatments", []
                ),
                "allergies_sensitivities": user_data.get("custom_fields", {}).get(
                    "allergies_sensitivities", []
                ),
            },
            "interests": user_data.get("interests", []),
            "goals": user_data.get("goals", []),
            "loved_ones": user_data.get("loved_ones", []),
            "activities_for_encouragement": user_data.get(
                "activities_for_encouragement", []
            ),
            "notes_for_ai": user_data.get("notes_for_ai", []),
            "created_at": now_timestamp_full(),
            "last_updated": now_timestamp_full(),
        }

    @staticmethod
    def _create_user_files_directly__save_json(file_path: str, data: dict):
        """Save data to a JSON file."""
        with open(file_path, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2, ensure_ascii=False)

    @staticmethod
    def _create_user_files_directly__schedules_data(categories: list) -> dict:
        """Create default schedule periods for categories."""
        if not categories:
            return {}

        schedules_data = {}
        for category in categories:
            schedules_data[category] = {
                "periods": {
                    "Morning": {
                        "active": True,
                        "days": ["ALL"],
                        "start_time": "09:00",
                        "end_time": "12:00",
                    },
                    "Afternoon": {
                        "active": True,
                        "days": ["ALL"],
                        "start_time": "13:00",
                        "end_time": "17:00",
                    },
                    "Evening": {
                        "active": True,
                        "days": ["ALL"],
                        "start_time": "18:00",
                        "end_time": "21:00",
                    },
                }
            }
        return schedules_data

    @staticmethod
    def _create_user_files_directly__message_files(user_dir: str, categories: list):
        """Create message directory and default message files."""
        # Ensure user directory exists before creating messages subdirectory (race condition fix)
        os.makedirs(user_dir, exist_ok=True)
        messages_dir = os.path.join(user_dir, "messages")
        os.makedirs(messages_dir, exist_ok=True)

        for category in categories:
            category_file = os.path.join(messages_dir, f"{category}.json")
            if not os.path.exists(category_file):
                # Ensure parent directory exists before writing (race condition fix)
                os.makedirs(os.path.dirname(category_file), exist_ok=True)
                with open(category_file, "w", encoding="utf-8") as f:
                    json.dump([], f, indent=2, ensure_ascii=False)

        # Create sent_messages.json
        sent_messages_file = os.path.join(messages_dir, "sent_messages.json")
        if not os.path.exists(sent_messages_file):
            # Ensure parent directory exists before writing (race condition fix)
            os.makedirs(os.path.dirname(sent_messages_file), exist_ok=True)
            with open(sent_messages_file, "w", encoding="utf-8") as f:
                json.dump([], f, indent=2, ensure_ascii=False)

    @staticmethod
    def create_basic_user__update_index(
        test_data_dir: str,
        user_id: str,
        actual_user_id: str,
        discord_user_id: str | None = None,
        email: str | None = None,
    ):
        """Update user index to map internal_username to UUID.

        Also adds mappings for Discord user ID and email if provided.
        Uses file locking to prevent race conditions in parallel test execution.
        """
        from core.file_locking import safe_json_read, safe_json_write

        user_index_file = os.path.join(test_data_dir, "user_index.json")

        # Read existing index with file locking
        user_index = safe_json_read(user_index_file, default={})

        # Add the new user to the index
        user_index[user_id] = actual_user_id

        # Add Discord user ID mapping if provided
        if discord_user_id:
            user_index[f"discord:{discord_user_id}"] = actual_user_id

        # Add email mapping if provided
        if email:
            user_index[f"email:{email}"] = actual_user_id

        # Save the updated index with file locking
        safe_json_write(user_index_file, user_index, indent=2)

    @staticmethod
    def _create_user_files_directly(
        user_id: str, user_data: dict[str, Any], test_data_dir: str
    ) -> str:
        """Helper function to create user files directly in test directory"""
        # Create user directory structure
        actual_user_id, user_dir = (
            TestUserFactory._create_user_files_directly__directory_structure(
                test_data_dir, user_id
            )
        )

        # Create data structures
        account_data = TestUserFactory._create_user_files_directly__account_data(
            actual_user_id, user_id, user_data
        )
        preferences_data = (
            TestUserFactory._create_user_files_directly__preferences_data(user_data)
        )
        context_data = TestUserFactory._create_user_files_directly__context_data(
            user_data
        )

        # Save main files
        account_file = os.path.join(user_dir, "account.json")
        preferences_file = os.path.join(user_dir, "preferences.json")
        context_file = os.path.join(user_dir, "user_context.json")

        TestUserFactory._create_user_files_directly__save_json(
            account_file, account_data
        )
        TestUserFactory._create_user_files_directly__save_json(
            preferences_file, preferences_data
        )
        TestUserFactory._create_user_files_directly__save_json(
            context_file, context_data
        )

        # Create schedules if categories exist
        categories = user_data.get("categories", [])
        if categories:
            schedules_data = (
                TestUserFactory._create_user_files_directly__schedules_data(categories)
            )
            schedules_file = os.path.join(user_dir, "schedules.json")
            TestUserFactory._create_user_files_directly__save_json(
                schedules_file, schedules_data
            )

        # Create message files
        TestUserFactory._create_user_files_directly__message_files(user_dir, categories)

        # Update user index with all mappings (username, Discord ID, email)
        discord_user_id = user_data.get("discord_user_id")
        email = user_data.get("email")
        TestUserFactory.create_basic_user__update_index(
            test_data_dir,
            user_id,
            actual_user_id,
            discord_user_id=discord_user_id,
            email=email,
        )

        return actual_user_id

