                "interests": ["Technology", "Gaming"],
                "goals": ["Improve mental health", "Stay organized"],
                "loved_ones": [],
                "activities_for_encouragement": [],
                "notes_for_ai": [],
            }

            # Create the user using the proper function
            actual_user_id = create_new_user(user_data)

